  "type": "CODE_BUILDER",
  "lessonText": "Explore the power of decorators and generators in Python through interactive coding.",
  "data": {
    "codeBuilder": {
      "avatarInstruction": "Create a decorator that logs the execution time of a function.",
      "lines": [
        {
          "content": "import time\n\ndef time_logger(func):\n    def wrapper(*args, **kwargs):\n        start_time = time.time()\n        result = func(*args, **kwargs)\n        end_time = time.time()\n        print(f'Execution time: {end_time - start_time} seconds')\n        return result\n    return wrapper"
        },
        {
          "content": "@time_logger\n\ndef example_function():\n    time.sleep(2)\n    return 'Function complete!'\n\nexample_function()"
        }
      ],
      "options": [
        "Create a generator that yields Fibonacci numbers.",
        "Implement a decorator that retries a function on failure.",
        "Design a generator that reads lines from a file.",
        "Write a decorator that checks function arguments."
      ]
    }
  }
}
